const data = $input.first().json.body;

// ═══════════════════════════════════════════════════════════════
// API ANAHTARLARINIZI BURAYA YAZIN
// ═══════════════════════════════════════════════════════════════
const ANTHROPIC_KEY = 'BURAYA_ANTHROPIC_API_KEY';  // Claude AI icin
const CLOUD_NAME = 'dm2jbdqxc';
const CLOUD_KEY = '723949127319764';
const CLOUD_SECRET = '9XsIgOi01RoxfE3PnRi0zWuZkEM';

async function uploadToCloudinary(base64Data, folder, resourceType = 'image') {
  const crypto = require('crypto');
  const ts = Math.floor(Date.now() / 1000).toString();
  const sig = crypto.createHash('sha1').update(`folder=${folder}&timestamp=${ts}${CLOUD_SECRET}`).digest('hex');
  const filePrefix = resourceType === 'raw' ? 'data:application/pdf;base64,' : 'data:image/png;base64,';
  const endpoint = resourceType === 'raw' ? 'raw' : 'image';
  const res = await fetch(`https://api.cloudinary.com/v1_1/${CLOUD_NAME}/${endpoint}/upload`, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({ file: `${filePrefix}${base64Data}`, api_key: CLOUD_KEY, timestamp: ts, signature: sig, folder })
  });
  const r = await res.json();
  if (!r.secure_url) throw new Error('Cloudinary upload failed: ' + JSON.stringify(r).slice(0, 200));
  return r.secure_url;
}

try {
  const productName = data.productName || 'Amigurumi';
  const title = data.title || productName;
  const description = data.description || '';
  const tags = data.tags || [];
  const images = data.generatedImages || [];

  // Claude AI ile profesyonel HTML PDF olustur
  const imageListHtml = images.map((img, i) => 
    `<div style="text-align:center;margin:10px;display:inline-block;width:45%;"><img src="${img.url}" style="max-width:100%;border-radius:8px;" /><p style="font-size:12px;color:#666;margin-top:4px;">${img.backgroundLabel || ('Gorsel ' + (i+1))}</p></div>`
  ).join('');

  const tagBadges = tags.map(t => 
    `<span style="display:inline-block;background:#f3e8ff;color:#7c3aed;padding:4px 12px;border-radius:20px;font-size:12px;margin:3px;">${t}</span>`
  ).join('');

  // Claude'dan profesyonel bir ozet iste
  let aiSummary = '';
  try {
    const claudeRes = await fetch('https://api.anthropic.com/v1/messages', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': ANTHROPIC_KEY,
        'anthropic-version': '2023-06-01'
      },
      body: JSON.stringify({
        model: 'claude-sonnet-4-20250514',
        max_tokens: 500,
        messages: [{
          role: 'user',
          content: `You are a professional Etsy listing expert. Write a short, compelling product summary (2-3 sentences) for this amigurumi product PDF listing sheet. Product: "${productName}". Title: "${title}". Description: "${description}". Write in English, make it sound professional and appealing for potential buyers.`
        }]
      })
    });
    const claudeData = await claudeRes.json();
    aiSummary = claudeData.content?.[0]?.text || '';
  } catch (e) {
    aiSummary = description.slice(0, 200);
  }

  // HTML sablonu olustur
  const html = `
<!DOCTYPE html>
<html>
<head><meta charset="UTF-8"><style>
  body { font-family: 'Segoe UI', Arial, sans-serif; margin: 0; padding: 40px; color: #1a1a2e; }
  .header { text-align: center; margin-bottom: 30px; padding-bottom: 20px; border-bottom: 3px solid #7c3aed; }
  .header h1 { font-size: 28px; color: #7c3aed; margin: 0 0 8px 0; }
  .header p { font-size: 14px; color: #666; margin: 0; }
  .section { margin-bottom: 25px; }
  .section h2 { font-size: 18px; color: #7c3aed; border-left: 4px solid #7c3aed; padding-left: 12px; margin-bottom: 12px; }
  .description { font-size: 14px; line-height: 1.6; color: #333; background: #faf5ff; padding: 16px; border-radius: 8px; }
  .ai-summary { font-size: 14px; line-height: 1.6; color: #4c1d95; background: #ede9fe; padding: 16px; border-radius: 8px; font-style: italic; }
  .tags { margin-top: 8px; }
  .images-grid { text-align: center; }
  .footer { text-align: center; margin-top: 30px; padding-top: 15px; border-top: 1px solid #e5e7eb; font-size: 11px; color: #999; }
</style></head>
<body>
  <div class="header">
    <h1>${title}</h1>
    <p>${productName} - Amigurumi Urun Listesi</p>
  </div>

  ${aiSummary ? `<div class="section"><h2>AI Ozet</h2><div class="ai-summary">${aiSummary}</div></div>` : ''}

  ${description ? `<div class="section"><h2>Urun Aciklamasi</h2><div class="description">${description.replace(/\n/g, '<br/>')}</div></div>` : ''}

  ${tags.length > 0 ? `<div class="section"><h2>Etsy Etiketleri (${tags.length})</h2><div class="tags">${tagBadges}</div></div>` : ''}

  ${images.length > 0 ? `<div class="section"><h2>Urun Gorselleri (${images.length})</h2><div class="images-grid">${imageListHtml}</div></div>` : ''}

  <div class="footer">
    <p>Amigurumi Panel - AI ile uretildi | ${new Date().toLocaleDateString('tr-TR')}</p>
  </div>
</body>
</html>`;

  // HTML'i base64 olarak Cloudinary'a yukle (raw olarak)
  const htmlBase64 = Buffer.from(html).toString('base64');
  const pdfUrl = await uploadToCloudinary(htmlBase64, 'amigurumi/pdf', 'raw');

  // Web panele sonucu gonder
  await fetch(data.callbackUrl, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      secret: data.secret,
      type: 'pdf-result',
      productId: data.productId,
      pdfUrl: pdfUrl
    })
  });

  return [{ json: { success: true, pdfUrl } }];

} catch (error) {
  try {
    await fetch(data.callbackUrl, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ secret: data.secret, type: 'error', productId: data.productId, error: error.message })
    });
  } catch {}
  throw error;
}
